exploreUrl:
@js:
let list = [];
let html = java.ajax("https://crxs.me/categories.html"); 
list.push({
    "title": "小说分类",
    "url": "",
    "style": { "layout_flexGrow": 1, "layout_flexBasisPercent": 1 }
});

let reg = /href="(\/fictions\/tag-\d+)\.html"[\s\S]*?<div class="title">([^<]+)<\/div>/g;
let match;
while ((match = reg.exec(html)) !== null) {
    list.push({
        "title": match[2],        
        "url": match[1] + "/{{page}}.html", 
        "style": {
            "layout_flexGrow": 1,
            "layout_flexBasisPercent": 0.2
        }
    });
}
JSON.stringify(list);
